import React from "react"
import { graphql } from 'gatsby'
import Layout from "../pages/layout"
import Footer from "../components/footer"
import "../styles/singleProject.scss"
import { Helmet } from "react-helmet"

export default function SingleProjectTemplate(props) {
    const d = (props.data && props.data.dataJson) ? props.data.dataJson : (props.pageContext && props.pageContext.data) ? props.pageContext.data : {}

    const renderTechs = () => {
        if (!d.techs) return null
        return d.techs.map(e => (
            <div className="single_project_tech" key={e.id || Math.random()}>
                <a href={e.url} aria-label={e.description}>
                    <img src={e.pic_url} alt={e.name} title={e.name} />
                </a>
            </div>
        ))
    }

    return (
        <Layout>
            <Helmet>
                <title>{d.name || 'Project'}</title>
                <meta name="description" content={d.description || ''} />
            </Helmet>

            <div className='single_project_container container'>
                <header className="project_description">{d.description}</header>
                <div className='project_techs'>
                    {renderTechs()}
                </div>
                {d.media ? <div className="project_media"><img src={d.media} alt={d.name} /></div> : null}
                <div className="project_story">{d.story}</div>
                <div className="project_links">
                    {d.git_link ? <a href={d.git_link}>GitHub</a> : null}
                    {d.web_link ? <a href={d.web_link} style={{ marginLeft: 8 }}>Live</a> : null}
                </div>
            </div>

            <Footer />
        </Layout>
    )
}

export const query = `
        query($slug: String!) {
                dataJson(fields: { slug: { eq: $slug } }) {
                        id,
                        date,
                        description,
                        git_link,
                        name,
                        story,
                        web_link,
                        media,
                        media_pre,
                        techs {
                                id,
                                description,
                                name,
                                pic_url,
                                tech_type,
                                url
                        }
                }
        }
`
